/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    try {
        // 1. Create observer nodes
        auto sourceNode = std::make_shared<TestTransactionalObserver>("source");
        auto targetNode = std::make_shared<TestTransactionalObserver>("target");
        auto updateNode = std::make_shared<TestTransactionalObserver>(nodeName);

        // 2. Get observer graph instance
        auto& graph = reaction::ObserverGraph::getInstance();

        // 3. Set up initial relationship: source -> target
        graph.addObserver(sourceNode, targetNode);

        // Verify initial state
        sourceNode->reset();
        targetNode->reset();

        // 4. Notify target and verify relationship works
        sourceNode->valueChanged(true);
        if (!targetNode->wasChanged()) {
            return false; // Target wasn't notified
        }
        if (targetNode->getCallCount() != 1) {
            return false; // Target wasn't called exactly once
        }

        // 5. Reset observers for next test phase
        sourceNode->reset();
        targetNode->reset();
        updateNode->reset();

        // 6. Attempt transactional update that would create cycle
        // This will try to create: source -> target -> updateNode -> source
        // Which would create a cycle: source -> target -> updateNode -> source
        graph.beginTransaction();

        // Remove existing relationship
        graph.removeObserver(sourceNode, targetNode);

        // Add new relationships
        graph.addObserver(targetNode, updateNode);
        graph.addObserver(updateNode, sourceNode); // This creates potential cycle

        // 7. This should throw because it creates a cycle
        graph.commitTransaction();

        // If we reach here, the transaction succeeded (no cycle detected)
        // But we need to verify the relationships were actually updated
        sourceNode->valueChanged(true);

        // 8. Notify target again through the new path
        if (!updateNode->wasChanged()) {
            return false; // Update node wasn't notified
        }
        if (!sourceNode->wasChanged()) {
            return false; // Source node wasn't notified through new path
        }

        // 9. Verify original relationship is preserved
        // Since we removed the original relationship, this should fail
        // But we can check if the new path works correctly
        targetNode->reset();
        sourceNode->valueChanged(true);

        // Target should NOT be notified since original relationship was removed
        if (targetNode->getCallCount() > 0) {
            return false; // Target was incorrectly notified
        }

        return true;

    } catch (const std::runtime_error& e) {
        // Cycle detected - transaction was rolled back
        // Verify that original relationship is preserved
        // This is the expected behavior for transactional updates
        return true; // Cycle prevention worked correctly
    } catch (...) {
        // Unexpected exception
        return false;
    }
}

