    std::vector<std::string> names;
    names.reserve(ordered.size());
    for (const auto &react : ordered) {
        names.push_back(react.getName());
    }

    bool unique = names.size() == 3;

    return OrderingSnapshot{
        .orderedNames = names,
        .allUnique = unique,
    };
}

