class DepthProbeNode : public reaction::ObserverNode {
public:
    DepthProbeNode(int depth) : m_depth(depth) {}

    void updateDepth(int newDepth) override {
        m_depth = newDepth;
        reaction::ObserverNode::updateDepth(newDepth);
    }

    int getDepth() const { return m_depth; }

private:
    int m_depth;
};

inline DepthOrderingSnapshot test_observer_depth_ordering() {
    auto& tm = reaction::ThreadManager::getInstance();
    tm.resetForTesting();
    tm.enableThreadSafety();

    // Create nodes with different depths
    auto shallowNode = std::make_shared<DepthProbeNode>(1);
    auto deepNode = std::make_shared<DepthProbeNode>(3);

    // Create weak references
    reaction::NodeWeak<DepthProbeNode> shallowWeak(shallowNode);
    reaction::NodeWeak<DepthProbeNode> deepWeak(deepNode);
    reaction::NodeWeak<DepthProbeNode> nullWeak;

    // Create batch comparator
    reaction::BatchCompare<DepthProbeNode> batchCompare;

    // Initial comparison (shallow depth 1 vs deep depth 3)
    bool initialResult = batchCompare.compareNodes(shallowNode, deepNode);
    // Should be true since shallow comes before deep by depth

    // Update depths to reverse order
    shallowNode->updateDepth(5);
    deepNode->updateDepth(2);

    // Now compare shallow (depth 5) vs deep (depth 2)
    bool shallowBeforeDeep = batchCompare.compareNodes(shallowNode, deepNode);
    // Should be true since shallow has higher depth (5 > 2)

    // Update to make deep deeper than shallow
    shallowNode->updateDepth(1);
